"use client";
import { useState } from "react";

export default function DealsForm() {
  const [form, setForm] = useState({
    description: "",
    currentPrice: "",
    oldPrice: "",
    storeName: "",
    imageLink: "",
    productLink: "",
    reviewLink: "",
    couponCode: "",
    shippingCost: "",
    notes: "",
    expireDate: "",
    category: "",
  });
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<string | null>(null);

  const onChange = (e: any) => setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async (e: any) => {
    e.preventDefault();
    setSaving(true);
    setMsg(null);

    try {
      const res = await fetch("/api/deals", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...form,
        published_at: new Date().toISOString(),
      }),
    });
      const data = await res.json();
      setSaving(false);

      if (!res.ok) {
        console.error("API error:", data);
        setMsg(`❌ ${data.error || "Failed to save"}`);
      } else {
        console.log("Deal saved:", data);
        setMsg("✅ Deal saved successfully!");
      }
    } catch (err: any) {
      console.error("Network error:", err);
      setMsg("❌ Network error");
      setSaving(false);
    }
  };

  return (
    <form
      onSubmit={onSubmit}
      className="bg-white shadow p-6 rounded-md space-y-4 max-w-2xl border border-gray-300"
    >
      <h2 className="text-xl font-semibold text-blue-600 mb-2">Add New Deal</h2>
      {msg && <div className="text-sm">{msg}</div>}

      <input name="description" value={form.description} onChange={onChange} placeholder="Description" className="input" />
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <input name="currentPrice" value={form.currentPrice} onChange={onChange} placeholder="Current Price" className="input" />
        <input name="oldPrice" value={form.oldPrice} onChange={onChange} placeholder="Old Price" className="input" />
        <input name="storeName" value={form.storeName} onChange={onChange} placeholder="Store Name" className="input" />
      </div>

      <input name="imageLink" value={form.imageLink} onChange={onChange} placeholder="Image Link" className="input" />
      <input name="productLink" value={form.productLink} onChange={onChange} placeholder="Product Link" className="input" />
      <input name="reviewLink" value={form.reviewLink} onChange={onChange} placeholder="Review Link" className="input" />
      <input name="couponCode" value={form.couponCode} onChange={onChange} placeholder="Coupon Code" className="input" />
      <input name="shippingCost" value={form.shippingCost} onChange={onChange} placeholder="Shipping Cost" className="input" />
      <textarea name="notes" value={form.notes} onChange={onChange} placeholder="Notes (bullet points)" className="input" />
      <input name="expireDate" value={form.expireDate} onChange={onChange} placeholder="Deal Expiry Date" className="input" />
      <input name="category" value={form.category} onChange={onChange} placeholder="Category" className="input" />

      <button
        type="submit"
        disabled={saving}
        className="w-full bg-blue-600 text-white p-2 rounded-md hover:bg-blue-700 transition"
      >
        {saving ? "Saving..." : "Save Deal"}
      </button>
    </form>
  );
}
